import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';
import { getNotifications, markNotificationsRead } from '@/lib/notificationService';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export async function GET(request: NextRequest) {
  try {
    const supabase = createClient(supabaseUrl, supabaseAnonKey);
    const token = request.headers.get('authorization')?.replace('Bearer ', '') || '';
    let userId = null;
      if (token) {
        try {
          const { data: { user }, error: authError } = await supabase.auth.getUser(token);
          if (authError) {
            // Expected in dev when token expires; reduce noise to warn
            console.warn('[notifications] Unauthorized:', authError?.message || authError);
            return NextResponse.json({ success: false, error: 'Unauthorized', notifications: [] }, { status: 401 });
          }
          userId = user?.id;
        } catch (err) {
          console.warn('[notifications] Unauthorized (exception during auth):', (err as any)?.message || err);
          return NextResponse.json({ success: false, error: 'Unauthorized', notifications: [] }, { status: 401 });
        }
    }
    
    if (!userId) {
      return NextResponse.json({ success: false, error: 'Unauthorized', notifications: [] }, { status: 401 });
    }

    // Paginated notifications
    const { searchParams } = new URL(request.url);
    const offset = Number(searchParams.get('offset')) || 0;
    const limit = Number(searchParams.get('limit')) || 20;
    const { data, error } = await getNotifications(userId, limit, offset);
    
    if (error) {
      console.error('[notifications] Query error:', error);
      return NextResponse.json({ success: false, error: error.message, notifications: [] }, { status: 500 });
    }
    
    return NextResponse.json({ success: true, notifications: data || [] });
  } catch (error: any) {
    console.error('[notifications] Unexpected error:', error);
    return NextResponse.json({ success: false, error: error.message, notifications: [] }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const supabase = createClient(supabaseUrl, supabaseAnonKey);
    const token = request.headers.get('authorization')?.replace('Bearer ', '') || '';
    let userId = null;
    if (token) {
      const { data: { user }, error: authError } = await supabase.auth.getUser(token);
      if (authError) {
        console.warn('[notifications] Unauthorized:', authError?.message || authError);
        return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
      }
      userId = user?.id || null;
    }
    
    if (!userId) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }

    const body = await request.json();
    const { action, notificationIds } = body;
    if (action === 'mark-read') {
      const { data, error } = await markNotificationsRead(userId, notificationIds);
      if (error) {
        console.error('[notifications] Mark read error:', error);
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
      }
      return NextResponse.json({ success: true, updated: data });
    }
    return NextResponse.json({ success: false, error: 'Invalid action' }, { status: 400 });
  } catch (error: any) {
    console.error('[notifications] Unexpected error:', error);
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}
